// Helper functions for tag form

func tagFormAction(data TagFormData) templ.SafeURL {
	if data.IsEdit && data.Tag != nil {
		return templ.SafeURL(fmt.Sprintf("/admin/tags/%d", data.Tag.ID))
	}
	return "/admin/tags"
}

func tagFormXData(data TagFormData) string {
	slug := tagFormValue(data, "slug")
	if data.IsEdit {
		return fmt.Sprintf(`{ slug: %s, slugEdited: true, generateSlug(value) { if (!this.slugEdited) { this.slug = value.toLowerCase().trim().replace(/[^\w\s-]/g, '').replace(/[\s_-]+/g, '-').replace(/^-+|-+$/g, ''); } } }`, strconv.Quote(slug))
	}
	return fmt.Sprintf(`{ slug: %s, slugEdited: false, generateSlug(value) { if (!this.slugEdited) { this.slug = value.toLowerCase().trim().replace(/[^\w\s-]/g, '').replace(/[\s_-]+/g, '-').replace(/^-+|-+$/g, ''); } } }`, strconv.Quote(slug))
}

func tagFormValue(data TagFormData, field string) string {
	if v, ok := data.FormValues[field]; ok && v != "" {
		return v
	}
	if data.Tag != nil {
		switch field {
		case "name":
			return data.Tag.Name
		case "slug":
			return data.Tag.Slug
		}
	}
	return ""
}

func currentLanguageCode(data TagFormData) string {
	if v, ok := data.FormValues["language_code"]; ok && v != "" {
		return v
	}
	if data.Language != nil {
		return data.Language.Code
	}
	if data.Tag != nil {
		return data.Tag.LanguageCode
	}
	return ""
}

func languageFieldName(isEdit bool) string {
	if isEdit {
		return "_language_code_disabled"
	}
	return "language_code"
}

func languageHiddenValue(data TagFormData) string {
	if data.Language != nil {
		return data.Language.Code
	}
	return ""
}

func tagFormTitle(pc *PageContext, isEdit bool) string {
	if isEdit {
		return pc.T("tags.edit")
	}
	return pc.T("tags.new")
}

func tagFormDescription(pc *PageContext, isEdit bool) string {
	if isEdit {
		return pc.T("tags.edit_description")
	}
	return pc.T("tags.new_description")
}

